def rob_ring(nums):
    if len(nums) == 1:
        return nums[0]
    def rob_line(arr):
        prev2, prev1 = 0, 0
        for x in arr:
            prev2, prev1 = prev1, max(prev1, prev2 + x)
        return prev1
    return max(rob_line(nums[:-1]), rob_line(nums[1:]))

